defmodule SessionPlug do
  @moduledoc """
  Plug for integrating SessionManager with Phoenix.
  Reads session from cookie on request, provides helpers for session manipulation.
  """

  import Plug.Conn

  @session_cookie "_app_session"
  @cookie_options [
    http_only: true,
    secure: true,
    same_site: "Strict",
    max_age: 86_400
  ]

  def init(opts), do: opts

  def call(conn, _opts) do
    session_cookie = conn |> fetch_cookies() |> Map.get(:cookies, %{}) |> Map.get(@session_cookie)

    case session_cookie do
      nil ->
        conn
        |> assign(:session_data, %{})
        |> assign(:session_valid, false)

      cookie_value ->
        case SessionManager.read_session(cookie_value) do
          {:ok, session_data} ->
            conn
            |> assign(:session_data, session_data)
            |> assign(:session_valid, true)

          {:error, _reason} ->
            # Invalid/expired/tampered session - clear it
            conn
            |> delete_resp_cookie(@session_cookie)
            |> assign(:session_data, %{})
            |> assign(:session_valid, false)
        end
    end
  end

  @doc """
  Sets session data and writes the signed cookie to the response.
  """
  def set_session(conn, data) when is_map(data) do
    signed_cookie = SessionManager.create_session(data)

    conn
    |> put_resp_cookie(@session_cookie, signed_cookie, @cookie_options)
    |> assign(:session_data, data)
    |> assign(:session_valid, true)
  end

  @doc """
  Destroys the session by clearing the cookie.
  """
  def destroy_session(conn) do
    conn
    |> delete_resp_cookie(@session_cookie)
    |> assign(:session_data, %{})
    |> assign(:session_valid, false)
  end
end